SELECT task_id AS taskId, bvid, video_title AS title, user_id AS userId, status, task_type AS taskType, progress, current_step AS currentStep, error_message AS errorMessage, comment_fetch_mode AS commentFetchMode, comment_risk_controlled AS commentRiskControlled, comment_fetch_retries AS commentFetchRetries, created_at AS createdAt, updated_at AS updatedAt, completed_at AS completedAt FROM analysis_task
user_id = #{userId}
ORDER BY created_at DESC LIMIT #{limit}
